PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>

SELECT DISTINCT ?secretary ?label
WHERE {
  wd:Q11231 p:P1313 ?statement .
  ?statement ps:P1313 ?secretary ;
             pq:P580 ?start ;
             pq:P582 ?end .
  FILTER(xsd:dateTime(?start) <= "2017-12-31T23:59:59Z"^^xsd:dateTime &&
         xsd:dateTime(?end) >= "2017-01-01T00:00:00Z"^^xsd:dateTime) .
  OPTIONAL { ?secretary rdfs:label ?label . FILTER(LANG(?label) = "en") }
}
ORDER BY ?start

